import java.util.Scanner;public class ExercicioVerificarJogador {    public static void main(String[] args) {        Scanner inputIdade = new Scanner(System.in);        System.out.println("Sua idade: ");        int idade = inputIdade.nextInt();        if (idade <= 18){            System.out.println("Você jogará na base do bangu!");        } else if (idade > 18 && idade <= 30){            System.out.println("Você está jogando profissionalmente pelo Santa Cruz");        } else {            System.out.println("Aposenta fi...");        }    }}